using (var et = new EntityTransaction<Administrator>())
{
    var admin = Administrator.FindByName("admin");
    admin.Logins++;
    admin.Update();

    et.Commit();
}

using (var et = new EntityTransaction(DAL.Create("Common")))
{
    var admin = Administrator.FindByName("admin");
    admin.Logins++;
    admin.Update();

    et.Commit();
}

member.remarks:
在 Search 方法中使用示例：

public static IList<Order> Search(Int32 status, PageParameter page)
{
    var exp = new WhereExpression();
    if (status >= 0) exp &= _.Status == status;

    // 同时应用租户和数据权限过滤
    exp = exp.ApplyScope<Order>();

    return FindAll(exp, page);
}

            用法：在实体类的静态构造函数中注册：

            static MyEntity()
            {
                Meta.Interceptors.Add<DataScopeInterceptor>();
            }


实体类需实现 IDataScope、IUserScope 或 IDepartmentScope 接口

运行时需设置 DataScopeContext.Current 或确保 ManageProvider.User 有效

查询时自动附加数据权限过滤条件，无需手动调用 ApplyDataScope

在 Search 方法中使用示例：

public static IList<Order> Search(Int32 status, PageParameter page)
{
    var exp = new WhereExpression();
    if (status >= 0) exp &= _.Status == status;

    // 应用租户过滤
    exp = exp.ApplyTenant<Order>();

    return FindAll(exp, page);
}

启动后监听HTTP端口，通过 DbController 提供数据库远程操作接口。
支持独立部署场景，也可以在ASP.NET应用中直接使用DbService。

用法示例：

var server = new DbServer();
server.Port = 3305;
server.Service.Tokens["mytoken"] = new[] { "Membership" };
server.Start();
